INSERT INTO public.photos VALUES (25528, 'Pontoneros 1982', 'Pontoneros del regimiento de Monzalbarba venidos del moderno cuartel de Sangenis, junto a un pont‚îú‚îÇn con funciones de muelle sobre el r‚îú¬°o Ebro durante una demostraci‚îú‚îÇn con notable expectaci‚îú‚îÇn de p‚îú‚ïëblico. La imagen ha sido capturada dando la espalda al Club Nataci‚îú‚îÇn Helios. A la izquierda, el puente de Santiago. Al fondo, torres de la iglesia de Santa Isabel, el colegio Valent‚îú¬°n Zabala, y varias construcciones en el entorno de la calle de Escobar, de Ab‚îú¬Æn Aire y de los Predicadores.', 1982, 1982, 1982, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65903300, -0.88172500, '0101000020E61000006519E2581737ECBF0DFE7E315BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14922153074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14922153074.webp', 'https://www.flickr.com/photos/zaragozaantigua/14922153074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25534, 'Pasarela sobre Ebro 1958', 'C‚îú¬Æsar Gracia Jarque. 1958. "R‚îú¬°o Ebro. La Pasarela". Imagen de la Pasarela desde la altura de la Hospeder‚îú¬°a del Pilar.', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15936514862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15936514862.webp', 'https://www.flickr.com/photos/zaragozaantigua/15936514862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25537, 'R‚îú¬°o Ebro 1931', 'Grupo de ba‚îú‚ñíistas en el r‚îú¬°o Ebro a su paso por Zaragoza, en 1931. Al fondo, el Pilar. Fuente: Revista Cr‚îú‚îÇnica. Madrid, 1931', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65908400, -0.88194800, '0101000020E610000034B91803EB38ECBF8FA850DD5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18765210669.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18765210669.webp', 'https://www.flickr.com/photos/zaragozaantigua/18765210669/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25543, 'Pasarela 1958', 'Pasarela peatonal tendida sobre el r‚îú¬°o Ebro en 1941, tambi‚îú¬Æn conocida como de Macanaz, y que supuso el final de los embarcaderos de la zona que hasta entonces se dedicaban al transporte de personas entre una y otra orilla, generalmente para acceder a la arboleda de Macanaz. Se mantuvo la navegaci‚îú‚îÇn recreativa. Esta paralela fue desmantelada en 1967 con motivo de la construcci‚îú‚îÇn del moderno puente de Santiago. En el Pilar, la obra de la nueva torre de San Francisco de Borja progresa m‚îú√≠s r‚îú√≠pido que la de Santa Leonor. Al fondo, el puente de Piedra y el de Hierro. Fuente visual: foto Jos‚îú¬Æ Antonio Duce, en rafaelcastillejo.com', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20525679189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20525679189.webp', 'https://www.flickr.com/photos/zaragozaantigua/20525679189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25570, 'R‚îú¬°o Ebro c.1931', 'Imagen capturada desde la arboleda de Macanaz y centrada en la barca del "T‚îú¬°o Toni" que con nutrida parroquia cruza el r‚îú¬°o de forma no mecanizada, a punto de llegar al embarcadero donde descender‚îú√≠ el pasaje venido de la margen derecha. La a‚îú¬Ærea sirga que posibilita la singladura aparece tendida y jalonando el recorrido. Otras embarcaciones recreativas, de menor tama‚îú‚ñío, hacia el fondo del cauce fluvial. Encuadra la escena la tradicional estampa del templo del Pilar con dos torres (la de Santiago, en primer t‚îú¬Ærmino, y la de Nuestra se‚îú‚ñíora del Pilar, junto a la c‚îú‚ïëpula mayor)', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65871900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBF7D2079E750D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48881459702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48881459702.webp', 'https://www.flickr.com/photos/zaragozaantigua/48881459702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25576, 'Embarcadero del Ebro 1932', 'Imagen capturada en el embarcadero que en la margen izquierda y desde 1929 daba servicio al nuevo transbordo del r‚îú¬°o Ebro mediante la lancha-gasolinera "Nuestra se‚îú‚ñíora del Pilar", aguas arriba del antiguo paso que mediante tradicional sirga realizaba la barca del T‚îú¬°o Toni, que en la fotograf‚îú¬°a se ve al fondo. Este nuevo servicio, asumido por Francisco S‚îú√≠nchez en r‚îú¬Ægimen de concesi‚îú‚îÇn, era muy apreciado por los vecinos del barrio de Macanaz y por los usuarios del Centro Deportivo "Helios". Se trata de una imagen tomada durante el viaje de bodas del autor de la misma, que en ella retrata a su esposa Emilia Marimon Rovira con el tradicional fondo edilicio de un brumoso templo del Pilar y los puentes de Piedra y de Hierro.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65911800, -0.88200600, '0101000020E61000005B069CA56439ECBF3B1A87FA5DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52993273588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52993273588.webp', 'https://www.flickr.com/photos/zaragozaantigua/52993273588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25975, 'Riada de 1961', 'Vista general de la margen izquierda durante la gran riada del Ebro de 1961. En primer plano se distinguen el edificio de los ba‚îú‚ñíos de las playas del Ebro y la torre de Helios. Fuente: Foto Mar‚îú¬°n Chivite. AMZ.', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65933400, -0.88266000, '0101000020E610000074982F2FC03EECBF0892770E65D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15134684919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15134684919.webp', 'https://www.flickr.com/photos/zaragozaantigua/15134684919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26064, 'Vista a‚îú¬Ærea c.1968', 'Imagen capturada desde notable altura sobre el barrio de la Ortilla, con una interesante vista a‚îú¬Ærea del tramo urbano del r‚îú¬°o Ebro comprendido entre el Puente de Santiago, en primer t‚îú¬Ærmino, y el puente de Hierro, alcanzando incluso hasta el nuevo Puente del Ferrocarril, al fondo. A la izquierda, la feraz arboleda de Macanaz sigue delimitada en buena parte por el enlace ferroviario. A la derecha y al fondo, en el barrio de Las Fuentes comienzan a surgir tambi‚îú¬Æn inmuebles que rompen la tradicional barrera de las 4-5 alturas, como el que se destaca en la plaza del Monasterio de San Victori‚îú√≠n. En esta perif‚îú¬Ærica ubicaci‚îú‚îÇn este fen‚îú‚îÇmeno llama la atenci‚îú‚îÇn, aunque nada comparado con los ejemplos que comenzaban a proliferar de forma salvaje en la ciudad consolidada.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65856500, -0.88030000, '0101000020E6100000CF66D5E76A2BECBF27A5A0DB4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49223352466.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49223352466.webp', 'https://www.flickr.com/photos/zaragozaantigua/49223352466/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20947, 'San Juan de los Panetes 1855', 'Dibujada desde el "paseo de Macanaz", esta vista de la orilla derecha reproduce el campanario y la cabecera de la iglesia de San Juan de los Panetes, el torre‚îú‚îÇn de la Zuda con piso a‚îú‚ñíadido y con un edificio de casi el mismo tama‚îú‚ñío adosado a su izquierda, junto al que destaca al fondo la Torre Nueva. En la muralla al Ebro, la puerta de San Ildefonso o de la Triper‚îú¬°a. Fuente visual de la imagen: Valent‚îú¬°n Carderera, en "Viaje art‚îú¬°stico por Arag‚îú‚îÇn de Valent‚îú¬°n Carderera", Jos‚îú¬Æ Mar‚îú¬°a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaci‚îú‚îÇn L‚îú√≠zaro Galdiano, 2013), recopilada, editada y comentada de forma exclusiva por el Gran Archivo Zaragoza Antigua (GAZA).', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65790400, -0.88140300, '0101000020E6100000CB1473107434ECBF2CF4C13236D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15082762216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15082762216.webp', 'https://www.flickr.com/photos/zaragozaantigua/15082762216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21058, 'Torre‚îú‚îÇn de la Zuda c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C‚îú¬°a. 1860-1886. "Torre de la Calle de Antonio P‚îú¬Ærez", o Torre‚îú‚îÇn de la Zuda (ss. I-XVI).', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65749100, -0.88157200, '0101000020E6100000CE37A27BD635ECBF093543AA28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866141862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866141862.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866141862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21076, 'Calle Antonio P‚îú¬Ærez c.1877', 'Los descartes desechados por Laurent y C‚îú¬°a para editar, al principio de la d‚îú¬Æcada de 1870, la producida imagen final de la "Torre de la calle de Antonio P‚îú¬Ærez", los reutilizamos para unos interesantes rescates visuales, incluyendo los m‚îú√≠rgenes marginados. A la izquierda, la nave de la nueva f‚îú√≠brica barroca de la iglesia de San Juan de los Panetes, con sus contrafuertes de apoyo a la nave central. En primer plano, los edificios a ambos lados de la calle de Antonio P‚îú¬Ærez, los n‚îú‚ïëmeros pares adosados a la muralla romana y al torre‚îú‚îÇn de la Zuda (ya despejado del parasitario torre‚îú‚îÇn que ten‚îú¬°a adosado), y los impares de la manzana de Paseo del Ebro-Antonio P‚îú¬Ærez-Culebra, desde donde se ha capturado la fotograf‚îú¬°a. A la derecha, torreones y remates del antiguo complejo hospitalario de la orden de San Juan, que en el momento de la captura visual era convento de las MM. Adoratrices Esclavas del Sant‚îú¬°simo Sacramento y de la Caridad. Y al fondo, la sorpresa final: emerge un pedacito del triple chapitel de la Torre Nueva. Fuente visual: Jean Laurent y C‚îú¬°a, Archivo Ruiz Vernacci (Fototeca del Patrimonio Hist‚îú‚îÇrico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22095267584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22095267584.webp', 'https://www.flickr.com/photos/zaragozaantigua/22095267584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21186, 'La Zuda 1890', 'Imagen centrada en el antiguo torre‚îú‚îÇn de la Zuda, integrado desde 1857 como parte del convento de la congregaci‚îú‚îÇn de las Adoratrices Esclavas del Sant‚îú¬°simo Sacramento y de la Caridad. Delante de ‚îú¬Æl, vista parcial de los edificios de viviendas a ‚îú¬Æl adosados desde la calle de Antonio P‚îú¬Ærez, n‚îú‚ïëmeros 16, y 18. Fuente visual: "Torre‚îú‚îÇn del Palacio de la Azuda", fototipia de Joarizti y Mariezcurrena, en √î√á¬£Zaragoza Art‚îú¬°stica, Monumental e Hist‚îú‚îÇrica√î√á√ò, Anselmo y Pedro Gasc‚îú‚îÇn de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34457567312.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34457567312.webp', 'https://www.flickr.com/photos/zaragozaantigua/34457567312/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22548, 'Colegio Santo Domingo de Silos c.1975', 'El colegio Obra Diocesana de Santo Domingo de Silos fue inaugurado en 1959. El enorme complejo, hoy ampliado con zonas deportivas junto al Tercer Cintur‚îú‚îÇn, est‚îú√≠ situado en el barrio de Las Fuentes, en la calle de la Amistad 9 (derecha de la foto a‚îú¬Ærea). En primer plano, la calle Fray Luis Urbano; en el lateral izquierdo, Rodrigo Rebolledo. Los edificios de la derecha, el Grupo Jos‚îú¬Æ Antonio Gir‚îú‚îÇn. Fuente visual: AMZ.', 1975, 1975, 1975, 'Anos 70', 'LAS FUENTES', 41.64646000, -0.85990600, '0101000020E61000002B4B74965984EBBF09168733BFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15022288080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15022288080.webp', 'https://www.flickr.com/photos/zaragozaantigua/15022288080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21269, 'Ribera del Ebro 1900', 'Imagen de la habitual feria del ganado en la ribera del Ebro, desde la calle del Fin, y hasta San Juan de los Panetes (al fondo), que con motivo de las Fiestas del Pilar, convert‚îú¬°a Zaragoza en un gran mercado, o feria ganadera, con participaci‚îú‚îÇn de bestias y personas de casi toda la ribera del Ebro, resultando un importante nivel de transacciones econ‚îú‚îÇmicas. Como suele ser norma en la vegetaci‚îú‚îÇn de la ribera, ‚îú¬Æsta va y viene seg‚îú‚ïën tiempos, y momentos. En este caso, la feria se pudo hacer bajo la sombra del extra‚îú‚ñío sol de octubre. Fuente visual: Diario "ABC".', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21637391743.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21637391743.webp', 'https://www.flickr.com/photos/zaragozaantigua/21637391743/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21564, 'Pilar 1929', '"Una vista de las torres del Pilar de Zaragoza", porque dos ya es plural, desde la foresta de la arboleda de Macanaz. A la derecha, el abigarrado conjunto de edificaciones entre la calle de los Agustinos, del Fin, el paseo del Ebro, y San Juan de los Panetes. Fuente visual: Ricardo Schmelz, revista "La Esfera" (Madrid).', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65759400, -0.88028000, '0101000020E610000008556AF6402BECBFDE054A0A2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22586884107.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22586884107.webp', 'https://www.flickr.com/photos/zaragozaantigua/22586884107/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21682, 'La Zuda 1930', 'Fotograf‚îú¬°a original de la imagen del Torre‚îú‚îÇn de la Zuda y San Juan de los Panetes, que, coloreada, apareci‚îú‚îÇ en la portada de la revista "Arag‚îú‚îÇn" en mayo de ese a‚îú‚ñío. Fuente visual: Archivo Juan Mora, AMZ.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65749100, -0.88157200, '0101000020E6100000CE37A27BD635ECBF093543AA28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877891000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877891000.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877891000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21704, 'Riada de 1930', 'Gran riada en el Ebro, vista por un grupo de personas desde el paseo de la Ribera. El barrio de Ranillas, a la izquierda, inundado. Las instalaciones de la Sociedad Naturista Helios, y Macanaz, a la derecha, tambi‚îú¬Æn. Fuente: foto Gil Marraco, en "El Ebro desbordado: una historia de las crecidas del r‚îú¬°o en Zaragoza". Ayuntamiento de Zaragoza, 2011.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65809700, -0.88189000, '0101000020E61000000D6C95607138ECBF404CC2853CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15752575315.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15752575315.webp', 'https://www.flickr.com/photos/zaragozaantigua/15752575315/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21789, 'San Juan de los Panetes 1934', 'Imagen capturada durante el largo, complicado y pol‚îú¬Æmico proceso de transformaci‚îú‚îÇn del antiguo, laber‚îú¬°ntico y enorme conjunto de la "iglesia de San Juan de los Panetes de la Religi‚îú‚îÇn de San Juan de Jerusal‚îú¬Æn, y la Casa y Palacio de la Castellan‚îú¬°a de Amposta". En esos momentos se estaba procediendo a derribar algunas dependencias del antiguo convento, cuyas ‚îú‚ïëltimas inquilinas hab‚îú¬°an sido miembros de la Congregaci‚îú‚îÇn de Adoratrices Esclavas del Sant‚îú¬°simo Sacramento y de la Caridad. El acceso a la iglesia se realizaba, bien por el peque‚îú‚ñío callej‚îú‚îÇn que desde la derecha comunicaba con la calle de los Agustinos, la plaza de Huesca, y la calle de la Zuda; o bien por otro estrecho callej‚îú‚îÇn que comunicaba con la plaza de San Ant‚îú‚îÇn. Fuente visual: Miguel Mar‚îú¬°n Chivite, Archivo P‚îú‚ïëblico Municipal.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23964636033.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23964636033.webp', 'https://www.flickr.com/photos/zaragozaantigua/23964636033/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21817, 'Embarcadero del Ebro a‚îú‚ñíos 30', 'Foto: Miguel Mar‚îú¬°n Chivite. Vista del embarcadero con una embarcaci‚îú‚îÇn a motor que cubr‚îú¬°a el recorrido de orilla a orilla del r‚îú¬°o Ebro. Estaba situado a la altura de la calle de Antonio P‚îú¬Ærez, en el desag‚îú‚ïùe del Mercado Central. Arriba se puede ver la sirga de las barcas de tracci‚îú‚îÇn humana. Fuente: Heraldo de Arag‚îú‚îÇn.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65801300, -0.88124900, '0101000020E61000001C3F541A3133ECBFE2AB1DC539D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31221034973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31221034973.webp', 'https://www.flickr.com/photos/zaragozaantigua/31221034973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21901, 'San Juan de los Panetes c.1932', 'Imagen centrada en la barroca fachada y torre de la iglesia de San Juan de los Panetes durante el proceso de derribo del antiguo convento hospitalario de la castellan‚îú¬°a de Amposta donde estaba inserta. A la derecha y en la umbr‚îú¬°a, callej‚îú‚îÇn de acceso desde la plaza de Huesca y traseras del inmueble del n‚î¨‚ïë 11 de la calle de la Zuda. En primer t‚îú¬Ærmino la chavaler‚îú¬°a juega en el talud producido durante la excavaci‚îú‚îÇn arqueol‚îú‚îÇgica realizada entre la iglesia y el tramo de murallas romanas de la Zuda.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65745900, -0.88155600, '0101000020E610000062F6B2EDB435ECBFFEBAD39D27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51421564681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51421564681.webp', 'https://www.flickr.com/photos/zaragozaantigua/51421564681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23689, 'Aer‚îú‚îÇdromo Sanjurjo 1937', 'Imagen capturada en el aer‚îú‚îÇdromo Sanjurjo tras el ataque que la Fuerza A‚îú¬Ærea Republicana llev‚îú‚îÇ a cabo el d‚îú¬°a 15 de octubre de 1937. Este "raid" estuvo protagonizado de buena madrugada por dos escuadrillas de cazas Polikarpov I-15 ("Chatos") con 21 aparatos, provenientes de Bujaraloz y Sari‚îú‚ñíena, y 5 escuadrillas de Polikarpov I-16 ("Moscas") con 64 aparatos provenientes de Caspe, H‚îú¬°jar, Escatr‚îú‚îÇn y Puig Moreno. Tras cuatro minutos de breve ataque, quedaron destruidos doce aparatos entre Ju-52 y He-46 alemanes, y Fiat CR-32 italianos, adem‚îú√≠s de afectar en distinto grado a varias decenas de otros. En la imagen, tres Fiat CR-32 "Chirri" destruidos sobre la pista del aer‚îú‚îÇdromo Sanjurjo de Zaragoza en Garrapinillos.', 1937, 1937, 1937, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52037632159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52037632159.webp', 'https://www.flickr.com/photos/zaragozaantigua/52037632159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21908, 'P.‚î¨‚ïë del Ebro c.1934', 'Imagen capturada en el paseo del Ebro junto al embarcadero ubicado a la altura de la calle de Antonio P‚îú¬Ærez cuando una "canoa autom‚îú‚îÇvil" maniobra posiblemente para dirigirse a la otra orilla del r‚îú¬°o, zona de la arboleda de Macanaz pr‚îú‚îÇxima a la municipal Caseta de los Ba‚îú‚ñíos. Este servicio funcionaba en el tramo fluvial comprendido entre el puente de Piedra y el puente del ferrocarril del Norte y estaba gestionado por un grupo de barqueros entre los que se encontraba Carlos Mar Sau, hijo del famoso "T‚îú¬°o Toni", barquero que desde mediados del siglo XIX y hasta pocos a‚îú‚ñíos antes de esta foto hizo historia en el imaginario popular de la ciudad. Esta moderna "canoa autom‚îú‚îÇvil" a motor, capaz de transportar hasta cien pasajeros por viaje, supuso en 1930 un gran cambio respecto a la barca que hasta entonces se desplazaba manualmente por el tradicional camino de sirga. Por ello el fot‚îú‚îÇgrafo titul‚îú‚îÇ esta imagen, de forma algo m‚îú√≠s rom‚îú√≠ntica, "Ferry with engine on Ebro. Formerly used current and wind" (Ferry con motor en el Ebro. Antes usaba la corriente y el viento). En primer t‚îú¬Ærmino, algunos espectadores contemplan desde la orilla las evoluciones de esta moderna barca motora.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65804400, -0.88170600, '0101000020E6100000B5FB5580EF36ECBF1DAA29C93AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51745928448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51745928448.webp', 'https://www.flickr.com/photos/zaragozaantigua/51745928448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21917, 'La Zuda c.1932', 'In‚îú¬Ædita imagen capturada junto a la portada de la iglesia de San Juan de los Panetes tras el derribo de buena parte del complejo ocupado por la congregaci‚îú‚îÇn de las Adoratrices hasta 1909. La fotograf‚îú¬°a se centra en el torre‚îú‚îÇn de la Zuda con el aspecto de su cara este que, en la parte inferior y junto a la puerta que aparece "colgada" en altura tras el derribo, se intuye el vano que alberga la placa instalada en 1885 que recordaba la reparaci‚îú‚îÇn del torre‚îú‚îÇn acometida "a expensas de la Casa de Mar‚îú¬°a Sant‚îú¬°sima de las Desamparadas" (referencia a las Adoratrices aqu‚îú¬° establecidas en 1857). Tras la restauraci‚îú‚îÇn integral del torre‚îú‚îÇn en los a‚îú‚ñíos 40 esta placa fue recolocada un poco m‚îú√≠s hacia la esquina de la derecha, tal y como es visible desde entonces.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65755500, -0.88170600, '0101000020E6100000B5FB5580EF36ECBF202922C32AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53241623602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53241623602.webp', 'https://www.flickr.com/photos/zaragozaantigua/53241623602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21934, 'La Zuda 1943', 'Archivo Municipal de Zaragoza. Archivo Mora "Torre‚îú‚îÇn de la Zuda."', 1943, 1943, 1943, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65749100, -0.88157200, '0101000020E6100000CE37A27BD635ECBF093543AA28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15066894912.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15066894912.webp', 'https://www.flickr.com/photos/zaragozaantigua/15066894912/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21943, 'Vista de Zaragoza 1940', 'Ayuntamiento de Zaragoza. Alberto Duce Baquero. 1940. Vista de Zaragoza Fuente: zaragozacool.blogspot.com.es/2010_05_01_archive.html', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65801200, -0.88167400, '0101000020E6100000DD787764AC36ECBF1230BABC39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15699718410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15699718410.webp', 'https://www.flickr.com/photos/zaragozaantigua/15699718410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21964, 'Plaza del Pilar 1949', 'Imagen de la ampliada y nueva plaza del Pilar en la zona de la antigua plaza de Huesca, despejada para ampliar la antigua plaza del Pilar, desde donde se realiza la captura, junto a uno de los ‚îú√≠rboles que le daban sombra. A la izquierda, el nuevo edificio para la Tienda Econ‚îú‚îÇmica y el Convento de las Hijas de la Caridad de Santa Ana, en cuya portada se incrustar‚îú√≠n los barrocos restos del ingreso al derribado Palacio de Sora. Enfrente, el "Monumento a los h‚îú¬Æroes y m‚îú√≠rtires de Zaragoza. Ca‚îú¬°dos en la Cruzada de Liberaci‚îú‚îÇn 1936-1939", en obras desde 1946, a‚îú‚ïën sin la cruz que lo coronar‚îú√≠. Detr‚îú√≠s, la iglesia de San Juan de los Panetes, y la fachada del nuevo convento de las Hermanas Misioneras Eucar‚îú¬°sticas de Nazareth, finalizando las obras de construcci‚îú‚îÇn. A la derecha, la Hospeder‚îú¬°a del Pilar, construida para la Sociedad Ang‚îú¬Ælica del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës. Un muestrario significativo de los valores de la Nueva Espa‚îú‚ñía victoriosa del comunismo. Fuente Visual: Fotos Ysa, Archivo P‚îú‚ïëblico Municipal.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21596013953.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21596013953.webp', 'https://www.flickr.com/photos/zaragozaantigua/21596013953/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22035, 'San Juan de los Panetes 1941', 'In‚îú¬Ædita imagen capturada desde el solar que ocupara el antiguo hospital de San Juan de la Orden del Temple, centrada en la barroca iglesia de San Juan de los Panetes originalmente de la Religi‚îú‚îÇn de San Juan de la Castellan‚îú¬°a de Amposta, tras el derribo de buena parte de los edificios que albergaron el convento de las Adoratrices aqu‚îú¬° establecido desde 1857 y hasta 1909. Destaca el aspecto "colgado" de la iglesia tras el rebaje del solar originario para igualarlo al de la nueva gran plaza del Pilar proyectada para por la derecha llegar hasta la calle de Don Jaime I. Algo m‚îú√≠s tarde aqu‚îú¬° se instalar‚îú¬°a una escalinata de piedra para poder acceder a la iglesia desde la altura del nuevo entorno. La precariedad del estado del templo queda evidenciada por el arbolito que despunta a la derecha del remate de su fachada, mientras que la torrecilla de la derecha apenas quedaba soportada por el muro al que estaba adosada, de forma que tuvo que ser apuntalada por detr‚îú√≠s. A la derecha, restos de la antigua muralla de piedra "aparecida" inopinadamente durante el derribo de las antiguas viviendas de ese lado de la calle de Antonio P‚îú¬Ærez, y al fondo, leve vista de uno de los postes met‚îú√≠licos que soportaban la pasarela peatonal tendida sobre el r‚îú¬°o Ebro y funcional desde el d‚îú¬°a 8 de febrero de 1941.', 1941, 1941, 1941, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65734600, -0.88138400, '0101000020E61000001AF7E6374C34ECBF0514EAE923D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53238458580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53238458580.webp', 'https://www.flickr.com/photos/zaragozaantigua/53238458580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22226, 'Plaza del Pilar c.1951', 'Imagen capturada desde cierta altura en la calle Imperial con vistas a la moderna plaza del Pilar. En primer t‚îú¬Ærmino y a la izquierda, la barroca iglesia de San Juan de los Panetes. Centran la escena las traseras del Monumento a los H‚îú¬Æroes y M‚îú√≠rtires de Nuestra Gloriosa Cruzada, flanqueado por la Hospeder‚îú¬°a del Pilar y la Tienda Econ‚îú‚îÇmica en el Convento de las Hijas de la Caridad de Santa Ana, donde destaca la reubicada puerta principal de acceso a la derribada casa de los marqueses de Torrecilla. Al fondo y tras la cruz, andamios de obra durante la construcci‚îú‚îÇn de la Casa del Cabildo, el Museo Catedralicio y el nuevo Colegio de los Infantes. La ampliada plaza del Pilar todav‚îú¬°a conserva el arbolado espacio que significaba la plaza del Pilar de toda la vida.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65721000, -0.88084800, '0101000020E61000007DE71725E82FECBF554D10751FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49189141817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49189141817.webp', 'https://www.flickr.com/photos/zaragozaantigua/49189141817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23744, 'Marlofa 1962', 'John "Ganso" Kovatch, militar del ej‚îú¬Ærcito de los EE.UU de Norteam‚îú¬Ærica destinado en la Base A‚îú¬Ærea de Zaragoza, haciendo turismo rural un d‚îú¬°a de permiso junto al r‚îú‚îÇtulo de Marlofa (La Joyosa), localidad apenas distante 500 metros de Zaragoza (Villarrapa). El r‚îú‚îÇtulo, rotulado convenientemente.', 1962, 1962, 1962, 'Anos 60', NULL, 41.73924000, -1.06816200, '0101000020E61000007C478D093117F1BF91F2936A9FDE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15211408905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15211408905.webp', 'https://www.flickr.com/photos/zaragozaantigua/15211408905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22239, 'Calle Imperial c.1951', 'Imagen capturada sobre las murallas de piedra romanas de la calle Imperial durante los trabajos de restauraci‚îú‚îÇn y recreaci‚îú‚îÇn de la misma. Un poco m‚îú√≠s adelante, traseras de las viviendas recayentes a la plaza de san Antonio Abad, luego derribadas. A la derecha, viviendas de la antigua calle de Antonio P‚îú¬Ærez, m‚îú√≠s tarde tambi‚îú¬Æn derribadas. Al fondo, el Mercado Central de Lanuza, luego propuesto para ser derribado, aunque felizmente no fue as‚îú¬°. Esta intervenci‚îú‚îÇn reconstructora aparece delimitada por un "muro de contenci‚îú‚îÇn" dentro del cual se obraba tambi‚îú¬Æn en la restauraci‚îú‚îÇn del Torre‚îú‚îÇn de la Zuda.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65723400, -0.88196300, '0101000020E61000008A0629780A39ECBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50949972821.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50949972821.webp', 'https://www.flickr.com/photos/zaragozaantigua/50949972821/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22248, 'Plaza del Pilar 1954', 'Imagen capturada en la plaza del Pilar durante la ceremonia de "consagraci‚îú‚îÇn de Espa‚îú‚ñía al inmaculado coraz‚îú‚îÇn de Mar‚îú¬°a" realizada como culminaci‚îú‚îÇn del Congreso Mariano celebrado en el marco de las fiestas del Pilar de ese a‚îú‚ñío. Un altar fue habilitado a tal efecto en el "monumento a los H‚îú¬Æroes de Zaragoza de la Gloriosa Cruzada", y una vez terminada la misa el "Jefe del Estado y General‚îú¬°simo" Francisco Franco Bahamonde, de rodillas, dio lectura ante la imagen procesional en plata de la virgen del Pilar del texto por el que se consagraba a Espa‚îú‚ñía "de manera solemne, oficial e irrevocable" a la referida advocaci‚îú‚îÇn. Al fondo, la Hospeder‚îú¬°a del Pilar, junto a la que aparece una tribuna cubierta ocupada por los arzobispos y obispos de toda Espa‚îú‚ñía.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65724200, -0.88094400, '0101000020E61000000470B378B130ECBF60C77F8120D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52272184910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52272184910.webp', 'https://www.flickr.com/photos/zaragozaantigua/52272184910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22271, 'La riada de 1961', 'Ayuntamiento de Zaragoza/Mar‚îú¬°n Chivite. Enero 1961. Se esperaba una crecida normalica, pero fue de a‚îú‚ïëpa: el Ebro se hizo mar y se subi‚îú‚îÇ hasta casi los 6,5 metros. Esta riada era solo comparable a aquella de enero de 1871, que dicen las cr‚îú‚îÇnicas que fue la madre de todas las crecidas. Los barrios m‚îú√≠s afectados fueron Ranillas, la Ortilla, Jes‚îú‚ïës, Arrabal. La magnitud no solo se debi‚îú‚îÇ a la cantidad de agua que llev‚îú‚îÇ el r‚îú¬°o (en Zaragoza se midieron m‚îú√≠s de 4 millones de litros por segundo), sino tambi‚îú¬Æn a su permanencia: hasta el 7 de enero no se apreci‚îú‚îÇ un decrecimiento notable. As‚îú¬° es el Ebro, ni m‚îú√≠s ni menos que un r‚îú¬°o mediterr‚îú√≠neo, con un caudal de agua tan variable que la siguiente riada nos parecer‚îú√≠ noticia. En la imagen, la crecida que convirti‚îú‚îÇ a la Pasarela en un ol‚îú¬°mpico trampol‚îú¬°n.', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65794000, -0.88119100, '0101000020E6100000F5F1D077B732ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14920612362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14920612362.webp', 'https://www.flickr.com/photos/zaragozaantigua/14920612362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22273, 'Margen Izquierda desde El Pilar 1968', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 18/05/1968. "Vistas de Zaragoza desde la torre del Pilar." Panor‚îú√≠mica perge‚îú‚ñíada para la ocasi‚îú‚îÇn, en una composici‚îú‚îÇn in‚îú¬Ædita, democr‚îú√≠tica, cient‚îú¬°fica y popular, generada en los laboratorios del', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65794000, -0.88119100, '0101000020E6100000F5F1D077B732ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14940178856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14940178856.webp', 'https://www.flickr.com/photos/zaragozaantigua/14940178856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22274, 'Glorieta P‚îú¬°o XII 1960', '1960. Heraldo de Arag‚îú‚îÇn. La Glorieta de P‚îú¬°o XII estaba situada entre el torre‚îú‚îÇn de la Zuda y San Juan de los Panetes, en una zona con pozo ornamental (hoy en el parque Grande, junto al jard‚îú¬°n bot‚îú√≠nico) y jardines. Vemos la pasarela previa al puente de Santiago, al fondo. Hoy la zona est‚îú√≠ arqueologizada, mostrando restos de la muralla romana.', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65759500, -0.88144400, '0101000020E61000006F2C280CCA34ECBFAE81AD122CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14948092592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14948092592.webp', 'https://www.flickr.com/photos/zaragozaantigua/14948092592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22329, 'Pl. del Pilar 1965', 'Como ven‚îú¬°a siendo tradicional-de toda la vida desde 1939, el 20-N era el d‚îú¬°a de Jos‚îú¬Æ Antonio y de los "ca‚îú¬°dos". Por ello, desde la Jefatura Provincial del Movimiento se organiz‚îú‚îÇ un programa de actos a tono, con un car‚îú√≠cter marcadamente nacional-cat‚îú‚îÇlico que implicaba a las organizaciones del ramo: FET y JONS, Vieja Guardia, Frente de Juventudes, Secci‚îú‚îÇn Femenina, SEU, SEM, Asociaci‚îú‚îÇn de ex Cautivos, Asociaci‚îú‚îÇn de ex Combatientes. Perfectamente uniformados con su identitaria camisa azul, acudir‚îú¬°an a todos los frentes ordenados: concentraciones ante el monumento a los "ca‚îú¬°dos"; rezo del rosario; toque de silencio, oraci‚îú‚îÇn y colocaci‚îú‚îÇn de corona de flores; canto del "Cara al sol"; misa, y solemne funeral. En la imagen, nocturna concentraci‚îú‚îÇn marcial del Frente de Juventudes ante el monumento a los "ca‚îú¬°dos" de la plaza del Pilar. Fue el 19 de noviembre, como antesala a lo programado para el d‚îú¬°a siguiente, desde el punto de la ma‚îú‚ñíana. Mientras tanto, y en su Escuela Hogar sita en el paseo de M‚î¨¬¨ Agust‚îú¬°n, la Secci‚îú‚îÇn Femenina estaba haciendo cosas de chicas: rezar el rosario, y leyendo el testamento de Primo de Rivera. Fuente visual: Archivo Municipal. Gerardo Sancho. 1965.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18523692289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18523692289.webp', 'https://www.flickr.com/photos/zaragozaantigua/18523692289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22440, 'San Juan de los Panetes 1965', 'Imagen del entorno de la iglesia de San Juan de los Panetes, capturada desde la altura de la antigua muralla de piedra de la ciudad, con el objetivo enfocando hacia el sureste, con el Altar de la Patria del R‚îú¬Ægimen, y la gran plaza del Pilar, hasta la Seo, al fondo. Fuente: www.todocoleccion.net/', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30962775146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30962775146.webp', 'https://www.flickr.com/photos/zaragozaantigua/30962775146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22697, 'Glorieta de P‚îú¬°o XII c.1972', 'Seis baturros con copla alusiva a la indumentaria de ellos, junto al Torre‚îú‚îÇn de la Zuda (izquierda). Al fondo, glorieta de P‚îú¬°o XII y arranque del Puente de Santiago. Tras la copla, espectadores. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65755400, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF4FADBEBA2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27347800801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27347800801.webp', 'https://www.flickr.com/photos/zaragozaantigua/27347800801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22707, 'La Zuda 1971', 'Calle Imperial, antigua de Antonio P‚îú¬Ærez y actual tramo de la avenida de C‚îú¬Æsar Augusto, con el renovado Torre‚îú‚îÇn de la Zuda y el tramo reconstruido de la antigua muralla de piedra, tras la que se encuentra la iglesia de San Juan de los Panetes, cuya torre despunta m‚îú¬°nimamente a la derecha. Al fondo, el paseo de Echegaray y Caballero y la arboleda de Macanaz, ya al otro lado del r‚îú¬°o Ebro y con acceso mediante el reciente puente de Santiago.', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65730800, -0.88196200, '0101000020E610000073124A5F0839ECBF18B325AB22D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27824111111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27824111111.webp', 'https://www.flickr.com/photos/zaragozaantigua/27824111111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22901, 'Plaza C‚îú¬Æsar Augusto 1989', 'Instant‚îú√≠nea de excavaciones arqueol‚îú‚îÇgicas en la plaza de C‚îú¬Æsar Augusto de Zaragoza, con el Torre‚îú‚îÇn de la Zuda y la iglesia de San Juan de los Panetes al fondo, el 2 de marzo de 1989. Fueron hallados mosaicos romanos, como el llamado "de las Musas", sobre el que vemos a los operarios. Ese mismo a‚îú‚ñío tambi‚îú¬Æn se hallaron y soterraron las cimentaciones de la puerta de Toledo, cerca de aqu‚îú¬°. En 1944 y en esta misma plaza apareci‚îú‚îÇ tambi‚îú¬Æn una villa romana, llamada Casa de Orfeo por el importante mosaico que albergaba (www.flickr.com/photos/zaragozaantigua/19113797851). Fuente: "Memoria de las calles de Zaragoza", Juli‚îú√≠n Ruiz Mar‚îú¬°n, Librer‚îú¬°a General, 1997.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65725700, -0.88162100, '0101000020E610000028F04E3E3D36ECBF960854FF20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21350613044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21350613044.webp', 'https://www.flickr.com/photos/zaragozaantigua/21350613044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23098, 'Av. de C‚îú¬Æsar Augusto 2000', 'A‚îú¬Ærea visual centrada en el entorno de la Zuda y San Juan de los Panetes durante las excavaciones arqueol‚îú‚îÇgicas realizadas a finales del pasado siglo XX en la glorieta de P‚îú¬°o XII para dejar al aire restos de la muralla romana e isl‚îú√≠mica. Fuente visual: AMZ.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23894210767.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23894210767.webp', 'https://www.flickr.com/photos/zaragozaantigua/23894210767/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23105, 'Torre‚îú‚îÇn de la Zuda 2000', 'Aspecto del acceso al Torre‚îú‚îÇn de la Zuda en 2000, durante su restauraci‚îú‚îÇn, que sac‚îú‚îÇ a la luz restos de las murallas romanas bajo la glorieta de P‚îú¬°o XII. Al fondo, lienzo musealizado en los a‚îú‚ñíos 50 en la calle Murallas Romanas. Fuente: Agencia EFE.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24349171610.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24349171610.webp', 'https://www.flickr.com/photos/zaragozaantigua/24349171610/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23813, 'Hospeder‚îú¬°a del Pilar 1940', 'Fase avanzada de construcci‚îú‚îÇn de la Hospeder‚îú¬°a del Pilar, junto a la Bas‚îú¬°lica (al fondo a la derecha). Ser‚îú√≠ inaugurada en enero de 1941. En el horizonte, el puente de Piedra sobre el Ebro. Fuente visual: "Una mirada a trav‚îú¬Æs de la arquitectura: Regino y Jos‚îú¬Æ Borobio Ojeda", Daniel Estab‚îú¬Æn Boldova, 2013.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65743500, -0.88004100, '0101000020E6100000CD7344BE4B29ECBF751F80D426D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15726203761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15726203761.webp', 'https://www.flickr.com/photos/zaragozaantigua/15726203761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23830, 'Paseo del Ebro 1907', 'Perspectiva del paseo del Ebro, desde las traseras del convento de San Juan de los Panetes (tras la caseta de consumos). Aqu‚îú¬° estaba la Puerta del Fin, y el desemboque de la calle del mismo nombre, y era lugar de posadas (como la de la imagen, en el n‚î¨‚ïë 39, donde la acumulaci‚îú‚îÇn de carros, recientemente proyectada por Jos‚îú¬Æ de Yarza, y denominada "Posada de Huesca"), caballerizas, veterinarios, aperos met‚îú√≠licos, y ferias de ganado. Fuente visual: Fototeca del Patrimonio Art‚îú¬°stico (www.mcu.es/)', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65759400, -0.88028000, '0101000020E610000008556AF6402BECBFDE054A0A2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21949447688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21949447688.webp', 'https://www.flickr.com/photos/zaragozaantigua/21949447688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23832, 'Calle del Fin, 1939', 'Imagen, en su ubicaci‚îú‚îÇn original, del escudo de armas del bar‚îú‚îÇn Don Hugo de Urri‚îú¬Æs y Veintemilla, un altorrelieve en piedra situado encima de la puerta de acceso a la iglesia del antiguo colegio de San Nicol‚îú√≠s Tolentino, en la desaparecida calle del Fin. Tras la Desamortizaci‚îú‚îÇn del siglo XIX, el edificio fue utilizado como almac‚îú¬Æn y reconvertido a casa de vecinos, y con el proyecto de la nueva y gran plaza del Pilar, el conjunto del colegio, la iglesia, y el anexo palacio de los patronos Urri‚îú¬Æs, fueron derribados y explanados en 1939, y sobre ellos se construyeron la nueva Hospeder‚îú¬°a para peregrinos, y la residencia del Cabildo de El Pilar, inaugurada en 1941. Seg‚îú‚ïën la prensa de la ‚îú¬Æpoca, el Ayuntamiento decidi‚îú‚îÇ preservar este escudo. Fuente visual: Juan Mora Insa, AMZ.', 1939, 1939, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65722600, -0.87978600, '0101000020E610000026512FF83427ECBF5B0A48FB1FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21953131280.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21953131280.webp', 'https://www.flickr.com/photos/zaragozaantigua/21953131280/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23897, 'Pl. del Pilar 1954', 'Imagen capturada durante el homenaje del Ej‚îú¬Ærcito espa‚îú‚ñíol a la Sant‚îú¬°sima Virgen celebrado en el marco del Congreso Mariano que tuvo lugar en la ciudad en octubre de ese a‚îú‚ñío. El altar de la marcial ceremonia se ubic‚îú‚îÇ en la altura del reci‚îú¬Æn terminado "Monumento a los h‚îú¬Æroes y m‚îú√≠rtires de Zaragoza. Ca‚îú¬°dos en la Cruzada de Liberaci‚îú‚îÇn 1936-1939", al oeste de la plaza del Pilar, tambi‚îú¬Æn denominada de las Catedrales desde que se culmin‚îú‚îÇ "la iniciativa de derribar casas viejas y barrios enteros para conseguir esta inmensa explanada en la que pueden celebrarse concentraciones de esta importancia, teniendo como fondo las dos catedrales zaragozanas: el Pilar y La Seo" (ABC, 9 de octubre de 1954). La imagen se ha tomado, precisamente, desde el referido monumento, con el fondo doblemente catedralicio, adem‚îú√≠s de los nuevos inmuebles del Gobierno Civil, y del Ayuntamiento (a‚îú‚ïën en construcci‚îú‚îÇn). Fuente visual: fondo Julio S‚îú√≠nchez Mill‚îú√≠n, en Ministerio de Cultura y Deporte.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65720400, -0.88098600, '0101000020E6100000C07B478D0931ECBF7366BB421FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45297598391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45297598391.webp', 'https://www.flickr.com/photos/zaragozaantigua/45297598391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23958, 'Avenida C‚îú¬Æsar Augusto 1987', 'Cortejo mortuorio y sentada para protestar contra la reforma universitaria del PSOE, durante unas de las numerosas movilizaciones que, tras las luchas estudiantiles en Francia e Italia de finales de 1986, en confluencia con las ense‚îú‚ñíanzas medias, y con el respaldo del rector, Vicente Camarena, caracterizaron los primeros meses de 1987. La escena tiene lugar donde la avenida de C‚îú¬Æsar Augusto desemboca en el paseo de Echegaray. A la derecha, el colegio Valent‚îú¬°n Zabala. Fuente: Zaragozarebelde.org', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65761900, -0.88182300, '0101000020E61000001A8A3BDEE437ECBF361D01DC2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14822243977.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14822243977.webp', 'https://www.flickr.com/photos/zaragozaantigua/14822243977/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23983, 'Plaza C‚îú¬Æsar Augusto 1987', 'Foto: ‚îú√ºngel de Castro. Atentado de ETA contra un autob‚îú‚ïës de la Academia General Militar el 30 de enero de 1987 en la plaza C‚îú¬Æsar Augusto de Zaragoza. A la derecha, el Torre‚îú‚îÇn de la Zuda y la iglesia de San Juan de los Panetes. Fuente: Heraldo de Arag‚îú‚îÇn.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65722000, -0.88135200, '0101000020E61000004374081C0934ECBF7923F3C81FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15411932322.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15411932322.webp', 'https://www.flickr.com/photos/zaragozaantigua/15411932322/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23747, 'Movera 1970', 'Grupo escolar y parroquial de la iglesia de Nuestra Se‚îú‚ñíora de Movera, reci‚îú¬Æn inaugurados, en la plaza de Espa‚îú‚ñía del hom‚îú‚îÇnimo barrio rural. Fuente visual: www.barriodemovera.es/', 1970, 1970, 1970, 'Anos 70', NULL, 41.64952200, -0.82180900, '0101000020E6100000F0DE5163424CEABF2904728923D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15500088328.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15500088328.webp', 'https://www.flickr.com/photos/zaragozaantigua/15500088328/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24078, 'Puente de Santiago 1967', 'Imagen capturada durante la inauguraci‚îú‚îÇn oficial del Puente de Santiago (13 de marzo) y centrada en el carrion‚îú¬Æs arzobispo de Zaragoza, Excelent‚îú¬°simo y Reverend‚îú¬°simo Se‚îú‚ñíor Pedro Cantero Cuadrado, cuando proced‚îú¬°a a rociar con agua bendita al nuevo nexo de uni‚îú‚îÇn entre ambas riberas del r‚îú¬°o Ebro que sustituy‚îú‚îÇ a la peatonal pasarela en servicio desde los a‚îú‚ñíos cuarenta. Mediante este sencillo acto el puente qued‚îú‚îÇ exortizado, purificado y pleno de gracia santificante. Tras el arzobispo complementan el cortejo inaugural diversas autoridades militares y civiles. Al fondo, legi‚îú‚îÇn de parroquianos que observan atentamente el ceremonial desde la elevada replaceta junto a la barroca iglesia de San Juan de los Panetes. Unos meses despu‚îú¬Æs, Pedro Cantero Cuadrado ser‚îú¬°a designado procurador en las Cortes Espa‚îú‚ñíolas por el Jefe del Estado, Francisco Franco Bahamonde. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38431721346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38431721346.webp', 'https://www.flickr.com/photos/zaragozaantigua/38431721346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
